/**
 * Semantic search functionality
 */

import * as fs from 'node:fs/promises'
import * as path from 'node:path'
import { Effect } from 'effect'
import {
  createStorage,
  loadDocumentIndex,
  loadSectionIndex,
} from '../index/storage.js'
import type { SectionEntry } from '../index/types.js'
import { createOpenAIProvider } from './openai-provider.js'
import type {
  EmbeddingProvider,
  SemanticSearchOptions,
  SemanticSearchResult,
  VectorEntry,
} from './types.js'
import { createVectorStore, type HnswVectorStore } from './vector-store.js'

// ============================================================================
// Embedding Text Generation
// ============================================================================

const generateEmbeddingText = (
  section: SectionEntry,
  documentTitle: string,
  parentHeading?: string | undefined,
): string => {
  const parts: string[] = []

  parts.push(section.heading)
  parts.push('')

  // We don't have the content here, so we'll use heading + context
  if (parentHeading) {
    parts.push(`Parent: ${parentHeading}`)
  }

  parts.push(`Document: ${documentTitle}`)

  return parts.join('\n')
}

// ============================================================================
// Build Embeddings
// ============================================================================

export interface BuildEmbeddingsOptions {
  readonly force?: boolean | undefined
  readonly provider?: EmbeddingProvider | undefined
}

export interface BuildEmbeddingsResult {
  readonly sectionsEmbedded: number
  readonly tokensUsed: number
  readonly cost: number
  readonly duration: number
}

export const buildEmbeddings = (
  rootPath: string,
  options: BuildEmbeddingsOptions = {},
): Effect.Effect<BuildEmbeddingsResult, Error> =>
  Effect.gen(function* () {
    const startTime = Date.now()
    const resolvedRoot = path.resolve(rootPath)
    const storage = createStorage(resolvedRoot)

    // Load indexes
    const docIndex = yield* loadDocumentIndex(storage)
    const sectionIndex = yield* loadSectionIndex(storage)

    if (!docIndex || !sectionIndex) {
      return yield* Effect.fail(
        new Error("Index not found. Run 'mdtldr index' first."),
      )
    }

    // Get or create provider
    const provider = options.provider ?? createOpenAIProvider()
    const dimensions = provider.dimensions

    // Create vector store
    const vectorStore = createVectorStore(
      resolvedRoot,
      dimensions,
    ) as HnswVectorStore
    vectorStore.setProvider(provider.name)

    // Load existing if not forcing
    if (!options.force) {
      const loaded = yield* vectorStore.load()
      if (loaded) {
        // For now, skip if any embeddings exist
        if (vectorStore.getStats().count > 0) {
          const duration = Date.now() - startTime
          return {
            sectionsEmbedded: 0,
            tokensUsed: 0,
            cost: 0,
            duration,
          }
        }
      }
    }

    // Prepare sections for embedding
    const sectionsToEmbed: { section: SectionEntry; text: string }[] = []

    for (const section of Object.values(sectionIndex.sections)) {
      const document = docIndex.documents[section.documentPath]
      if (!document) continue

      // Skip very short sections (< 10 tokens)
      if (section.tokenCount < 10) continue

      // Find parent heading if any
      let parentHeading: string | undefined
      if (section.level > 1) {
        const docSections = sectionIndex.byDocument[document.id] ?? []
        for (const sibId of docSections) {
          const sib = sectionIndex.sections[sibId]
          if (
            sib &&
            sib.level === section.level - 1 &&
            sib.startLine < section.startLine
          ) {
            parentHeading = sib.heading
          }
        }
      }

      const text = generateEmbeddingText(section, document.title, parentHeading)
      sectionsToEmbed.push({ section, text })
    }

    if (sectionsToEmbed.length === 0) {
      const duration = Date.now() - startTime
      return {
        sectionsEmbedded: 0,
        tokensUsed: 0,
        cost: 0,
        duration,
      }
    }

    // Generate embeddings
    const texts = sectionsToEmbed.map((s) => s.text)
    const result = yield* Effect.tryPromise({
      try: () => provider.embed(texts),
      catch: (e) =>
        new Error(
          `Embedding failed: ${e instanceof Error ? e.message : String(e)}`,
        ),
    })

    // Create vector entries
    const entries: VectorEntry[] = []
    for (let i = 0; i < sectionsToEmbed.length; i++) {
      const { section } = sectionsToEmbed[i] ?? { section: null }
      const embedding = result.embeddings[i]
      if (!section || !embedding) continue

      entries.push({
        id: section.id,
        sectionId: section.id,
        documentPath: section.documentPath,
        heading: section.heading,
        embedding,
      })
    }

    // Add to vector store
    yield* vectorStore.add(entries)
    vectorStore.addCost(result.cost, result.tokensUsed)

    // Save
    yield* vectorStore.save()

    const duration = Date.now() - startTime

    return {
      sectionsEmbedded: entries.length,
      tokensUsed: result.tokensUsed,
      cost: result.cost,
      duration,
    }
  })

// ============================================================================
// Semantic Search
// ============================================================================

export const semanticSearch = (
  rootPath: string,
  query: string,
  options: SemanticSearchOptions = {},
): Effect.Effect<readonly SemanticSearchResult[], Error> =>
  Effect.gen(function* () {
    const resolvedRoot = path.resolve(rootPath)

    // Get provider for query embedding
    const provider = createOpenAIProvider()
    const dimensions = provider.dimensions

    // Load vector store
    const vectorStore = createVectorStore(resolvedRoot, dimensions)
    const loaded = yield* vectorStore.load()

    if (!loaded) {
      return yield* Effect.fail(
        new Error("Embeddings not found. Run 'mdtldr embed' first."),
      )
    }

    // Embed the query
    const queryResult = yield* Effect.tryPromise({
      try: () => provider.embed([query]),
      catch: (e) =>
        new Error(
          `Query embedding failed: ${e instanceof Error ? e.message : String(e)}`,
        ),
    })

    const queryVector = queryResult.embeddings[0]
    if (!queryVector) {
      return yield* Effect.fail(new Error('Failed to generate query embedding'))
    }

    // Search
    const limit = options.limit ?? 10
    const threshold = options.threshold ?? 0

    const searchResults = yield* vectorStore.search(
      queryVector,
      limit * 2,
      threshold,
    )

    // Apply path filter if specified
    let filteredResults = searchResults
    if (options.pathPattern) {
      const pattern = options.pathPattern
        .replace(/\./g, '\\.')
        .replace(/\*/g, '.*')
      const regex = new RegExp(`^${pattern}$`, 'i')
      filteredResults = searchResults.filter((r) => regex.test(r.documentPath))
    }

    // Convert to SemanticSearchResult
    const results: SemanticSearchResult[] = filteredResults
      .slice(0, limit)
      .map((r) => ({
        sectionId: r.sectionId,
        documentPath: r.documentPath,
        heading: r.heading,
        similarity: r.similarity,
      }))

    return results
  })

// ============================================================================
// Search with Content
// ============================================================================

export const semanticSearchWithContent = (
  rootPath: string,
  query: string,
  options: SemanticSearchOptions = {},
): Effect.Effect<readonly SemanticSearchResult[], Error> =>
  Effect.gen(function* () {
    const resolvedRoot = path.resolve(rootPath)
    const results = yield* semanticSearch(resolvedRoot, query, options)

    const storage = createStorage(resolvedRoot)
    const sectionIndex = yield* loadSectionIndex(storage)

    if (!sectionIndex) {
      return results
    }

    const resultsWithContent: SemanticSearchResult[] = []

    for (const result of results) {
      const section = sectionIndex.sections[result.sectionId]
      if (!section) {
        resultsWithContent.push(result)
        continue
      }

      const filePath = path.join(resolvedRoot, result.documentPath)

      try {
        const fileContent = yield* Effect.promise(() =>
          fs.readFile(filePath, 'utf-8'),
        )

        const lines = fileContent.split('\n')
        const content = lines
          .slice(section.startLine - 1, section.endLine)
          .join('\n')

        resultsWithContent.push({
          ...result,
          content,
        })
      } catch {
        resultsWithContent.push(result)
      }
    }

    return resultsWithContent
  })

// ============================================================================
// Get Embedding Stats
// ============================================================================

export interface EmbeddingStats {
  readonly hasEmbeddings: boolean
  readonly count: number
  readonly provider: string
  readonly dimensions: number
  readonly totalCost: number
  readonly totalTokens: number
}

export const getEmbeddingStats = (
  rootPath: string,
): Effect.Effect<EmbeddingStats, Error> =>
  Effect.gen(function* () {
    const resolvedRoot = path.resolve(rootPath)

    // Try to load with default dimensions
    const vectorStore = createVectorStore(resolvedRoot, 1536)
    const loaded = yield* vectorStore.load()

    if (!loaded) {
      return {
        hasEmbeddings: false,
        count: 0,
        provider: 'none',
        dimensions: 0,
        totalCost: 0,
        totalTokens: 0,
      }
    }

    const stats = vectorStore.getStats()
    return {
      hasEmbeddings: true,
      count: stats.count,
      provider: stats.provider,
      dimensions: stats.dimensions,
      totalCost: stats.totalCost,
      totalTokens: stats.totalTokens,
    }
  })

/**
 * CLI Utility Functions
 *
 * Shared helper functions used across CLI commands.
 */

import * as fsPromises from 'node:fs/promises'
import * as path from 'node:path'

/**
 * Format object as JSON string
 */
export const formatJson = (obj: unknown, pretty: boolean): string => {
  return pretty ? JSON.stringify(obj, null, 2) : JSON.stringify(obj)
}

/**
 * Check if filename is a markdown file
 */
export const isMarkdownFile = (filename: string): boolean => {
  return filename.endsWith('.md') || filename.endsWith('.mdx')
}

/**
 * Recursively walk directory and collect markdown files
 */
export const walkDir = async (dir: string): Promise<string[]> => {
  const files: string[] = []
  const entries = await fsPromises.readdir(dir, { withFileTypes: true })

  for (const entry of entries) {
    const fullPath = path.join(dir, entry.name)

    // Skip hidden directories and node_modules
    if (entry.name.startsWith('.') || entry.name === 'node_modules') {
      continue
    }

    if (entry.isDirectory()) {
      const subFiles = await walkDir(fullPath)
      files.push(...subFiles)
    } else if (entry.isFile() && isMarkdownFile(entry.name)) {
      files.push(fullPath)
    }
  }

  return files
}

/**
 * Check if a query looks like a regex pattern
 */
export const isRegexPattern = (query: string): boolean => {
  // Has regex special characters (excluding simple spaces and common punctuation)
  return /[.*+?^${}()|[\]\\]/.test(query)
}

/**
 * Check if embeddings exist for a directory
 */
export const hasEmbeddings = async (dir: string): Promise<boolean> => {
  const vectorsPath = path.join(dir, '.md-tldr', 'vectors.bin')
  try {
    await fsPromises.access(vectorsPath)
    return true
  } catch {
    return false
  }
}

/**
 * INDEX Command
 *
 * Index markdown files for fast searching.
 */

import * as path from 'node:path'
import { Args, Command, Options } from '@effect/cli'
import { Console, Effect } from 'effect'
import { buildEmbeddings } from '../../embeddings/semantic-search.js'
import { buildIndex } from '../../index/indexer.js'
import { watchDirectory } from '../../index/watcher.js'
import { forceOption, jsonOption, prettyOption } from '../options.js'
import { formatJson } from '../utils.js'

export const indexCommand = Command.make(
  'index',
  {
    path: Args.directory({ name: 'path' }).pipe(
      Args.withDescription('Directory to index'),
      Args.withDefault('.'),
    ),
    embed: Options.boolean('embed').pipe(
      Options.withAlias('e'),
      Options.withDescription('Also build semantic embeddings'),
      Options.withDefault(false),
    ),
    watch: Options.boolean('watch').pipe(
      Options.withAlias('w'),
      Options.withDescription('Watch for changes'),
      Options.withDefault(false),
    ),
    force: forceOption,
    json: jsonOption,
    pretty: prettyOption,
  },
  ({ path: dirPath, embed, watch: watchMode, force, json, pretty }) =>
    Effect.gen(function* () {
      const resolvedDir = path.resolve(dirPath)

      if (watchMode) {
        yield* Console.log(`Watching ${resolvedDir} for changes...`)
        yield* Console.log('Press Ctrl+C to stop.')
        yield* Console.log('')

        const watcher = yield* watchDirectory(resolvedDir, {
          force,
          onIndex: (result) => {
            if (json) {
              console.log(formatJson(result, pretty))
            } else {
              console.log(
                `Re-indexed ${result.documentsIndexed} documents (${result.duration}ms)`,
              )
            }
          },
          onError: (error) => {
            console.error(`Watch error: ${error.message}`)
          },
        })

        yield* Effect.async<never, never>(() => {
          process.on('SIGINT', () => {
            watcher.stop()
            console.log('\nStopped watching.')
            process.exit(0)
          })
        })
      } else {
        yield* Console.log(`Indexing ${resolvedDir}...`)

        const result = yield* buildIndex(resolvedDir, { force })

        if (!json) {
          yield* Console.log('')
          // Show totals, with "newly indexed" count if incremental
          const newlyIndexed =
            result.documentsIndexed < result.totalDocuments
              ? ` (${result.documentsIndexed} updated)`
              : ''
          yield* Console.log(
            `Indexed ${result.totalDocuments} documents${newlyIndexed}`,
          )
          yield* Console.log(`  Sections: ${result.totalSections}`)
          yield* Console.log(`  Links: ${result.totalLinks}`)
          yield* Console.log(`  Duration: ${result.duration}ms`)

          if (result.errors.length > 0) {
            yield* Console.log('')
            yield* Console.log(`Errors (${result.errors.length}):`)
            for (const error of result.errors) {
              yield* Console.log(`  ${error.path}: ${error.message}`)
            }
          }
        }

        // Build embeddings if requested
        if (embed) {
          yield* Console.log('')
          yield* Console.log('Building embeddings...')

          const embedResult = yield* buildEmbeddings(resolvedDir, { force })

          if (!json) {
            yield* Console.log(
              `Embedded ${embedResult.sectionsEmbedded} sections`,
            )
            yield* Console.log(`  Tokens used: ${embedResult.tokensUsed}`)
            yield* Console.log(`  Cost: $${embedResult.cost.toFixed(6)}`)
            yield* Console.log(`  Duration: ${embedResult.duration}ms`)
          }
        }

        if (json) {
          yield* Console.log(formatJson(result, pretty))
        }
      }
    }),
).pipe(Command.withDescription('Index markdown files'))

/**
 * OpenAI embedding provider
 */

import OpenAI from 'openai'
import type { EmbeddingProvider, EmbeddingResult } from './types.js'

// ============================================================================
// Cost Constants
// ============================================================================

// Prices per 1M tokens (as of 2024)
const PRICING: Record<string, number> = {
  'text-embedding-3-small': 0.02,
  'text-embedding-3-large': 0.13,
  'text-embedding-ada-002': 0.1,
}

// ============================================================================
// OpenAI Provider
// ============================================================================

export interface OpenAIProviderOptions {
  readonly apiKey?: string | undefined
  readonly model?: string | undefined
  readonly batchSize?: number | undefined
}

export class OpenAIProvider implements EmbeddingProvider {
  readonly name: string
  readonly dimensions: number

  private readonly client: OpenAI
  private readonly model: string
  private readonly batchSize: number

  constructor(options: OpenAIProviderOptions = {}) {
    const apiKey = options.apiKey ?? process.env.OPENAI_API_KEY
    if (!apiKey) {
      throw new Error(
        'OpenAI API key required. Set OPENAI_API_KEY env var or pass apiKey option.',
      )
    }

    this.client = new OpenAI({ apiKey })
    this.model = options.model ?? 'text-embedding-3-small'
    this.batchSize = options.batchSize ?? 100
    this.name = `openai:${this.model}`
    this.dimensions = this.model === 'text-embedding-3-large' ? 3072 : 1536
  }

  async embed(texts: string[]): Promise<EmbeddingResult> {
    if (texts.length === 0) {
      return { embeddings: [], tokensUsed: 0, cost: 0 }
    }

    const allEmbeddings: number[][] = []
    let totalTokens = 0

    // Process in batches
    for (let i = 0; i < texts.length; i += this.batchSize) {
      const batch = texts.slice(i, i + this.batchSize)

      const response = await this.client.embeddings.create({
        model: this.model,
        input: batch,
      })

      for (const item of response.data) {
        allEmbeddings.push(item.embedding)
      }

      totalTokens += response.usage?.total_tokens ?? 0
    }

    // Calculate cost
    const pricePerMillion = PRICING[this.model] ?? 0.02
    const cost = (totalTokens / 1_000_000) * pricePerMillion

    return {
      embeddings: allEmbeddings,
      tokensUsed: totalTokens,
      cost,
    }
  }
}

// ============================================================================
// Factory
// ============================================================================

export const createOpenAIProvider = (
  options?: OpenAIProviderOptions,
): EmbeddingProvider => new OpenAIProvider(options)

/**
 * SEARCH Command
 *
 * Search markdown content by meaning or heading pattern.
 */

import * as path from 'node:path'
import { Args, Command, Options } from '@effect/cli'
import { Console, Effect, Option } from 'effect'
import { semanticSearch } from '../../embeddings/semantic-search.js'
import { search, searchContent } from '../../search/searcher.js'
import { jsonOption, prettyOption } from '../options.js'
import { formatJson, hasEmbeddings, isRegexPattern } from '../utils.js'

export const searchCommand = Command.make(
  'search',
  {
    query: Args.text({ name: 'query' }).pipe(
      Args.withDescription('Search query (natural language or regex pattern)'),
    ),
    path: Args.directory({ name: 'path' }).pipe(
      Args.withDescription('Directory to search in'),
      Args.withDefault('.'),
    ),
    structural: Options.boolean('structural').pipe(
      Options.withAlias('s'),
      Options.withDescription('Force structural search (headings only)'),
      Options.withDefault(false),
    ),
    headingOnly: Options.boolean('heading-only').pipe(
      Options.withAlias('H'),
      Options.withDescription('Search headings only (not content)'),
      Options.withDefault(false),
    ),
    mode: Options.choice('mode', ['semantic', 'structural']).pipe(
      Options.withAlias('m'),
      Options.withDescription('Force search mode: semantic or structural'),
      Options.optional,
    ),
    limit: Options.integer('limit').pipe(
      Options.withAlias('n'),
      Options.withDescription('Maximum results'),
      Options.withDefault(10),
    ),
    threshold: Options.float('threshold').pipe(
      Options.withDescription('Similarity threshold for semantic search (0-1)'),
      Options.withDefault(0.5),
    ),
    context: Options.integer('context').pipe(
      Options.withAlias('C'),
      Options.withDescription(
        'Lines of context around matches (like grep -C)',
      ),
      Options.optional,
    ),
    beforeContext: Options.integer('before-context').pipe(
      Options.withAlias('B'),
      Options.withDescription(
        'Lines of context before matches (like grep -B)',
      ),
      Options.optional,
    ),
    afterContext: Options.integer('after-context').pipe(
      Options.withAlias('A'),
      Options.withDescription('Lines of context after matches (like grep -A)'),
      Options.optional,
    ),
    json: jsonOption,
    pretty: prettyOption,
  },
  ({
    query,
    path: dirPath,
    structural,
    headingOnly,
    mode,
    limit,
    threshold,
    context,
    beforeContext,
    afterContext,
    json,
    pretty,
  }) =>
    Effect.gen(function* () {
      const resolvedDir = path.resolve(dirPath)

      // Check for embeddings
      const embedsExist = yield* Effect.promise(() =>
        hasEmbeddings(resolvedDir),
      )

      // Determine search mode
      // Priority: --mode flag > --structural flag > regex pattern > embeddings availability
      let useStructural: boolean
      let modeReason: string

      const modeValue = Option.getOrUndefined(mode)

      if (modeValue === 'semantic') {
        if (!embedsExist) {
          yield* Effect.fail(
            new Error(
              'Semantic search requires embeddings. Run "mdtldr index --embed" first.',
            ),
          )
        }
        useStructural = false
        modeReason = '--mode semantic'
      } else if (modeValue === 'structural') {
        useStructural = true
        modeReason = '--mode structural'
      } else if (structural) {
        useStructural = true
        modeReason = '--structural flag'
      } else if (isRegexPattern(query)) {
        useStructural = true
        modeReason = 'regex pattern detected'
      } else if (!embedsExist) {
        useStructural = true
        modeReason = 'no embeddings'
      } else {
        useStructural = false
        modeReason = 'embeddings available'
      }

      const modeIndicator = useStructural ? '[structural]' : '[semantic]'

      // Calculate context lines
      // -C sets both before and after; -B and -A override individual sides
      const contextValue = Option.getOrUndefined(context)
      const beforeValue = Option.getOrUndefined(beforeContext)
      const afterValue = Option.getOrUndefined(afterContext)

      const contextBefore = beforeValue ?? contextValue ?? 1
      const contextAfter = afterValue ?? contextValue ?? 1

      if (useStructural) {
        // Structural search - content by default, heading-only if flag set
        const results = headingOnly
          ? yield* search(resolvedDir, { heading: query, limit })
          : yield* searchContent(resolvedDir, {
              content: query,
              limit,
              contextBefore,
              contextAfter,
            })

        if (json) {
          const output = {
            mode: 'structural',
            modeReason,
            query,
            contextBefore,
            contextAfter,
            results: results.map((r) => ({
              path: r.section.documentPath,
              heading: r.section.heading,
              level: r.section.level,
              tokens: r.section.tokenCount,
              line: r.section.startLine,
              matches: r.matches?.map((m) => ({
                lineNumber: m.lineNumber,
                line: m.line,
                contextLines: m.contextLines,
              })),
            })),
          }
          yield* Console.log(formatJson(output, pretty))
        } else {
          const searchType = headingOnly ? 'Heading' : 'Content'
          yield* Console.log(
            `${modeIndicator} ${searchType} search: "${query}"`,
          )
          yield* Console.log(`Results: ${results.length}`)
          yield* Console.log('')

          for (const result of results) {
            const levelMarker = '#'.repeat(result.section.level)
            yield* Console.log(
              `  ${result.section.documentPath}:${result.section.startLine}`,
            )
            yield* Console.log(
              `    ${levelMarker} ${result.section.heading} (${result.section.tokenCount} tokens)`,
            )

            // Show match snippets with line numbers
            if (result.matches && result.matches.length > 0) {
              yield* Console.log('')
              for (const match of result.matches.slice(0, 3)) {
                // Show first 3 matches per section
                // Use contextLines for formatted output with line numbers
                if (match.contextLines && match.contextLines.length > 0) {
                  for (const ctxLine of match.contextLines) {
                    const marker = ctxLine.isMatch ? '>' : ' '
                    yield* Console.log(
                      `  ${marker} ${ctxLine.lineNumber}: ${ctxLine.line}`,
                    )
                  }
                } else {
                  // Fallback to simple snippet display
                  yield* Console.log(`    Line ${match.lineNumber}:`)
                  const snippetLines = match.snippet.split('\n')
                  for (const line of snippetLines) {
                    yield* Console.log(`      ${line}`)
                  }
                }
                yield* Console.log('')
              }
              if (result.matches.length > 3) {
                yield* Console.log(
                  `    ... and ${result.matches.length - 3} more matches`,
                )
              }
            }
            yield* Console.log('')
          }
        }
      } else {
        // Semantic search
        const results = yield* semanticSearch(resolvedDir, query, {
          limit,
          threshold,
        })

        if (json) {
          const output = {
            mode: 'semantic',
            modeReason,
            query,
            results,
          }
          yield* Console.log(formatJson(output, pretty))
        } else {
          yield* Console.log(`${modeIndicator} Semantic search: "${query}"`)
          yield* Console.log(`Results: ${results.length}`)
          yield* Console.log('')

          for (const result of results) {
            const similarity = (result.similarity * 100).toFixed(1)
            yield* Console.log(`  ${result.documentPath}`)
            yield* Console.log(`    ${result.heading} (${similarity}% match)`)
            yield* Console.log('')
          }
        }
      }
    }),
).pipe(Command.withDescription('Search by meaning or structure'))

